class Solution:
    def solve(self, nums, target):
        def backtrack(index, sum_):
            if index == len(nums): return sum_ == target
            for i in range(len(nums)):
                if (bitmask & (1 << nums[i])) != 0: continue
                bitmask |= (1 << nums[i])
                if backtrack(index + 1, sum_ + nums[i]): return True
                bitmask &= ~(1 << nums[i])
            return False
        n = nums[0]
        bitmask = 0
        return backtrack(1, 0)


