// Read input from std::cin
#include <iostream>
#include <vector>
#include <algorithm>
#include <utility>
using namespace std;

bool solve(vector<int>& nums, int target) {
    bool solve(int n, int index, int sum, int bitmask) {
        if (index == n) return sum == target;
        for (int i = 0; i < n; i++) {
            if ((bitmask & (1 << nums[i])) != 0) continue;
            bitmask |= (1 << nums[i]);
            if (solve(n, index + 1, sum + nums[i], bitmask)) return true;
            bitmask &= ~(1 << nums[i]);
        }
        return false;
    }
    n = nums[0];
    int bitmask = 0;
    return solve(n, 1, 0, bitmask);
}

int main() {
    int t;
    cin >> t;
    while (t--) {
        int n, target;
        cin >> n >> target;
        vector<int> nums(n);
        for (int &num : nums) cin >> num;
        cout << (solve(nums, target) ? "true" : "false") << endl;
    }
    return 0;
}
